import { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

export default function DriverCompletedTasks() {
 const [tasks, setTasks] = useState([]);

useEffect(() => {
  fetchCompletedTasks();
}, []);

const fetchCompletedTasks = async () => {
  try {
    const res = await axios.get(Api.completed_Task);

    if (res.data.success) {
      setTasks(res.data.data);
    }
  } catch (error) {
    console.log(error);
  }
};

return (
  <>
    <div className=" bg-[#4CBB17]/40 px-8">
        <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
          <img
            src="garbageVehicle.jpeg"
            alt="CleanTrack Logo"
            className="w-16 h-16 object-contain"
          />

          CleanTrack
        </h1>
        <p className="text-gray-900  p-2  ">
          Smart Waste Management Control Center
        </p>
    </div>
  <div className="min-h-screen bg-[#4CBB17]/20 p-8 ">
    <h1 className="text-4xl font-bold text-green-900 mb-8 text-center">
      Completed Tasks
    </h1>

    {tasks.length === 0 ? (
      <div className="bg-white p-8 rounded-xl shadow text-center">
        No Completed Tasks Found
      </div>
    ) : (
      <div className="grid md:grid-cols-3 gap-4">
        {tasks.map((task) => (
          <div
            key={task._id}
            className="bg-white border rounded-2xl p-5 hover:shadow-lg transition"
          >
            <p className="text-xs text-gray-500 flex justify-between">
              <span>
              REQUEST #{task._id.slice(-4)}
              </span>

              <span className="bg-green-500 text-white px-4 py-1 rounded-full">
                Completed
              </span>
            </p>

            <h3 className="text-xl font-semibold text-green-800 mt-1">
              📍 {task.location?.location}
            </h3>

            <div className=" items-center mt-4">
              <span className="font-medium">
                Priority: {task.priority}
              </span>

              
            </div>

            <p className="text-sm text-gray-500 mt-4">
              Created:{" "}
              {task.createdAt &&
                new Date(task.createdAt).toLocaleString("en-IN", {
                  day: "2-digit",
                  month: "short",
                  year: "numeric",
                  hour: "2-digit",
                  minute: "2-digit",
                  hour12: true,
                })}
            </p>

            {task.scheduledDate && (
              <p className="text-sm text-sky-700 mt-2 font-medium">
                Scheduled:{" "}
                {new Date(task.scheduledDate).toLocaleDateString(
                  "en-IN",
                  {
                    day: "2-digit",
                    month: "short",
                    year: "numeric",
                  }
                )}
                {" | "}
                  {new Date(req.scheduledTime).toLocaleTimeString("en-IN", {
        hour: "2-digit",
        minute: "2-digit",
        hour12: true,
      })}
              </p>
            )}

            {task.arrivedAt && (
              <p className="text-sm text-orange-700 mt-2 font-medium">
                Arrived:{" "}
                {new Date(task.arrivedAt).toLocaleString("en-IN", {
                  day: "2-digit",
                  month: "short",
                  year: "numeric",
                  hour: "2-digit",
                  minute: "2-digit",
                  hour12: true,
                })}
              </p>
            )}

            {task.completedAt && (
              <p className="text-sm text-green-700 mt-2 font-medium">
                Completed:{" "}
                {new Date(task.completedAt).toLocaleString("en-IN", {
                  day: "2-digit",
                  month: "short",
                  year: "numeric",
                  hour: "2-digit",
                  minute: "2-digit",
                  hour12: true,
                })}
              </p>
            )}
          </div>
        ))}
      </div>
    )}
  </div>
    </>

);
}
